.t-cell {
  display: flex;
  width: 100%;
  padding: 16px;
  background: #fff;
  font-size: 16px;
  line-height: 24px;
  color: #181818;
  box-sizing: border-box;

  &--align-top    { align-items: flex-start; }
  &--align-middle { align-items: center; }
  &--align-bottom { align-items: flex-end; }

  &--bordered { border-bottom: 1px solid #e7e7e7; }
  &--hover:active,
  &--active   { background: #f3f3f3; }
  &--disabled { color: #bbb; cursor: not-allowed; }
  &--arrow    { cursor: pointer; }

  &__main { flex: 1; min-width: 0; }
  &__title       { display: flex; align-items: center; gap: 4px; }
  &__required    { color: #d54941; font-weight: bold; }
  &__description { margin-top: 4px; font-size: 14px; color: #888; }
  &__note        { margin-left: 12px; color: #888; font-size: 14px; }
  &__left-icon   { margin-right: 12px; display: inline-flex; align-items: center; }
  &__right-icon,
  &__arrow       { margin-left: 8px; color: #c5c5c5; display: inline-flex; align-items: center; }
}

/**
 * Cell 组件类型契约
 */

export type CellAlign = 'top' | 'middle' | 'bottom';

export interface CellProps {
  /** 标题文案（与 #title 插槽二选一） */
  title?: string;
  /** 描述文案（与 #description 插槽二选一） */
  description?: string;
  /** 右侧值（与 #note 插槽二选一） */
  note?: string;
  /** 是否显示右箭头；string 时作为图标名（PoC 阶段仅控制是否显示） */
  arrow?: boolean;
  /** 是否显示下边框 */
  bordered?: boolean;
  /** 是否启用 hover 高亮 */
  hover?: boolean;
  /** 是否禁用 */
  disabled?: boolean;
  /** 是否必填（在 title 前显示红色星号） */
  required?: boolean;
  /** 主轴对齐 */
  align?: CellAlign;
  /** 透传额外类名 */
  customClass?: string;
}

export interface CellEmits {
  (e: 'click', event: MouseEvent): void;
}

import { cva } from '../../utils/cva';

export const cellVariants = cva('t-cell', {
  variants: {
    align: {
      top: 't-cell--align-top',
      middle: 't-cell--align-middle',
      bottom: 't-cell--align-bottom',
    },
    bordered: { true: 't-cell--bordered' },
    hover: { true: 't-cell--hover' },
    disabled: { true: 't-cell--disabled' },
    arrow: { true: 't-cell--arrow' },
  },
  defaultVariants: {
    align: 'middle',
  },
});
